+++ b/src/app/auth/callback/route.ts
@@ -0,0 +1,30 @@
+import { NextResponse } from "next/server";
+
+import { safeNext } from "@/lib/auth/safe-redirect";
+import { createClient } from "@/lib/supabase/server";
+
+// Where the OAuth handshake and the (default) email-confirmation link land. Both
+// flows arrive here with a `?code=` that we exchange for a session; the server
+// client writes the session cookies as part of the exchange.
+export async function GET(request: Request) {
+  const { searchParams, origin } = new URL(request.url);
+  const code = searchParams.get("code");
+  const next = safeNext(searchParams.get("next"));
+
+  if (code) {
+    const supabase = await createClient();
+    const { error } = await supabase.auth.exchangeCodeForSession(code);
+    if (!error) {
+      // Behind Vercel the public host is in x-forwarded-host, not the internal
+      // origin. Honour it in production so the redirect keeps the right domain.
+      const forwardedHost = request.headers.get("x-forwarded-host");
+      const isLocal = process.env.NODE_ENV === "development";
+      if (!isLocal && forwardedHost) {
+        return NextResponse.redirect(`https://${forwardedHost}${next}`);
+      }
+      return NextResponse.redirect(`${origin}${next}`);
+    }
+  }
+
+  return NextResponse.redirect(`${origin}/auth/auth-code-error`);
+}

diff --git a/src/app/auth/confirm/route.ts b/src/app/auth/confirm/route.ts
new file mode 100644
index 0000000..269eaa5
--- /dev/null
+++ b/src/app/auth/confirm/route.ts
@@ -0,0 +1,36 @@
+import { NextResponse } from "next/server";
+
+import { safeNext } from "@/lib/auth/safe-redirect";
+import { createClient } from "@/lib/supabase/server";
+
+// The email one-time-token flow: magic links, recovery, and confirmation emails
+// whose template points here with `?token_hash=&type=`. verifyOtp establishes
+// the session. (The default Supabase confirmation template uses /auth/callback
+// instead; this route covers the token_hash style and future password resets.)
+type EmailOtpType =
+  | "signup"
+  | "invite"
+  | "magiclink"
+  | "recovery"
+  | "email_change"
+  | "email";
+
+export async function GET(request: Request) {
+  const { searchParams, origin } = new URL(request.url);
+  const tokenHash = searchParams.get("token_hash");
+  const type = searchParams.get("type") as EmailOtpType | null;
+  const next = safeNext(searchParams.get("next"));
+
+  if (tokenHash && type) {
+    const supabase = await createClient();
+    const { error } = await supabase.auth.verifyOtp({
+      type,
+      token_hash: tokenHash,
+    });
+    if (!error) {
+      return NextResponse.redirect(`${origin}${next}`);
+    }
+  }
+
+  return NextResponse.redirect(`${origin}/auth/auth-code-error`);
+}

