+++ b/src/components/work-title.tsx
@@ -0,0 +1,45 @@
+import { formatCatalogId } from "@/lib/catalog";
+
+// The canonical way AIRED renders a work: AIRED-#### · "Title" (CLAUDE.md §2).
+// The catalog number anchors (mono, cert-red); the title sings (larger, bright).
+// `size` keeps one component usable both in a list row and as a page heading.
+export function WorkTitle({
+  id,
+  title,
+  size = "md",
+  className = "",
+}: {
+  id: number | bigint;
+  title: string;
+  size?: "sm" | "md" | "lg";
+  className?: string;
+}) {
+  const layout =
+    size === "lg"
+      ? "gap-1"
+      : "flex-row flex-wrap items-baseline gap-x-2 gap-y-0.5";
+  const idClass =
+    size === "lg" ? "text-sm" : size === "sm" ? "text-[11px]" : "text-xs";
+  const titleClass =
+    size === "lg"
+      ? "text-2xl font-semibold sm:text-3xl"
+      : size === "sm"
+        ? "text-sm font-medium"
+        : "text-base font-medium";
+
+  return (
+    <span className={`flex ${size === "lg" ? "flex-col" : ""} ${layout} ${className}`}>
+      <span
+        className={`font-mono uppercase tracking-[0.16em] text-cert-red ${idClass}`}
+      >
+        {formatCatalogId(id)}
+      </span>
+      <span aria-hidden className="text-muted/50">
+        ·
+      </span>
+      <span className={`text-foreground ${titleClass}`}>
+        &ldquo;{title}&rdquo;
+      </span>
+    </span>
+  );
+}

diff --git a/src/lib/auth/actions.ts b/src/lib/auth/actions.ts
new file mode 100644
index 0000000..94c0adf
--- /dev/null
+++ b/src/lib/auth/actions.ts
@@ -0,0 +1,108 @@
+"use server";
+
+import { revalidatePath } from "next/cache";
+import { headers } from "next/headers";
+import { redirect } from "next/navigation";
+
+import { createClient } from "@/lib/supabase/server";
+
+// Result returned to the form via useActionState. `error` shows inline; `notice`
+// carries a non-error message (e.g. "check your email"). A redirect on success
+// means the happy path never returns a value.
+export type AuthState = { error?: string; notice?: string } | undefined;
+
+// The site's own origin, for building auth redirect URLs. The `origin` header is
+// present on same-origin form POSTs; we fall back to the forwarded host so this
+// is correct behind Vercel's proxy and in local dev alike.
+async function getOrigin(): Promise<string> {
+  const h = await headers();
+  const origin = h.get("origin");
+  if (origin) return origin;
+  const host = h.get("x-forwarded-host") ?? h.get("host") ?? "localhost:3000";
+  const proto =
+    h.get("x-forwarded-proto") ?? (host.startsWith("localhost") ? "http" : "https");
+  return `${proto}://${host}`;
+}
+
+export async function signIn(
+  _prev: AuthState,
+  formData: FormData,
+): Promise<AuthState> {
+  const email = String(formData.get("email") ?? "").trim();
+  const password = String(formData.get("password") ?? "");
+  if (!email || !password) {
+    return { error: "Enter your email and password." };
+  }
+
+  const supabase = await createClient();
+  const { error } = await supabase.auth.signInWithPassword({ email, password });
+  if (error) {
+    return { error: error.message };
+  }
+
+  // The root layout reads the user, so refresh it before leaving.
+  revalidatePath("/", "layout");
+  redirect("/registry");
+}
+
+export async function signUp(
+  _prev: AuthState,
+  formData: FormData,
+): Promise<AuthState> {
+  const email = String(formData.get("email") ?? "").trim();
+  const password = String(formData.get("password") ?? "");
+  if (!email || !password) {
+    return { error: "Enter your email and password." };
+  }
+  if (password.length < 8) {
+    return { error: "Password must be at least 8 characters." };
+  }
+
+  const supabase = await createClient();
+  const origin = await getOrigin();
+  const { data, error } = await supabase.auth.signUp({
+    email,
+    password,
+    options: { emailRedirectTo: `${origin}/auth/callback?next=/registry` },
+  });
+  if (error) {
+    return { error: error.message };
+  }
+
+  // If the project has email confirmation off, signUp returns a live session and
+  // the user is already in. Otherwise we wait for them to confirm by email.
+  if (data.session) {
+    revalidatePath("/", "layout");
+    redirect("/registry");
+  }
+
+  return {
+    notice:
+      "Check your email to confirm your account, then come back and log in.",
+  };
+}
+
+// Google sign-in. This kicks off the OAuth handshake and redirects the browser
+// to Google; the round-trip lands back on /auth/callback. Requires the Google
+// provider to be enabled in the Supabase dashboard with OAuth credentials.
+export async function signInWithGoogle(): Promise<void> {
+  const supabase = await createClient();
+  const origin = await getOrigin();
+  const { data, error } = await supabase.auth.signInWithOAuth({
+    provider: "google",
+    options: { redirectTo: `${origin}/auth/callback?next=/registry` },
+  });
+  if (error) {
+    redirect(`/auth/auth-code-error?reason=${encodeURIComponent(error.message)}`);
+  }
+  if (data.url) {
+    redirect(data.url);
+  }
+}
+
+export async function signOut(): Promise<void> {
+  const supabase = await createClient();
+  await supabase.auth.signOut();
+  revalidatePath("/", "layout");
+  redirect("/");
+}

diff --git a/src/lib/auth/safe-redirect.ts b/src/lib/auth/safe-redirect.ts
new file mode 100644
index 0000000..14ac519
--- /dev/null
+++ b/src/lib/auth/safe-redirect.ts
@@ -0,0 +1,12 @@
+// Only ever redirect to a path on our own site. `next` arrives from a query
+// string (email links, OAuth state), so an attacker could try `//evil.com` or
+// `https://evil.com`. Accept a single-slash absolute path and nothing else.
+export function safeNext(
+  next: string | null | undefined,
+  fallback = "/registry",
+): string {
+  if (!next) return fallback;
+  if (!next.startsWith("/")) return fallback;
+  if (next.startsWith("//")) return fallback;
+  return next;
+}

diff --git a/src/lib/supabase/auth.ts b/src/lib/supabase/auth.ts
new file mode 100644
index 0000000..afeba58
--- /dev/null
+++ b/src/lib/supabase/auth.ts
@@ -0,0 +1,15 @@
+import { cache } from "react";
+
+import { createClient } from "./server";
+
+// The current signed-in user, verified against the Supabase Auth server.
+// Wrapped in React `cache` so multiple Server Components in one render (the
+// header and a page, say) share a single round-trip. Returns null when signed
+// out. Authorization still belongs at the data layer (RLS); this is for UI.
+export const getCurrentUser = cache(async () => {
+  const supabase = await createClient();
+  const {
+    data: { user },
+  } = await supabase.auth.getUser();
+  return user;
+});

diff --git a/src/lib/supabase/proxy.ts b/src/lib/supabase/proxy.ts
new file mode 100644
index 0000000..c578823
--- /dev/null
+++ b/src/lib/supabase/proxy.ts
@@ -0,0 +1,44 @@
+import { createServerClient } from "@supabase/ssr";
+import { NextResponse, type NextRequest } from "next/server";
+
+import { SUPABASE_ANON_KEY, SUPABASE_URL } from "./config";
+
+// Session refresh for AIRED, run from the Next.js 16 Proxy (the renamed
+// Middleware — see node_modules/next/dist/docs/.../proxy.md). The browser holds
+// the Supabase session in cookies; on every request we read it, let the client
+// rotate an expired access token, and write the fresh cookies back onto the
+// response. Skipping this is the classic cause of users being randomly logged
+// out, so the refresh call must run with nothing between it and the client.
+export async function updateSession(request: NextRequest) {
+  let response = NextResponse.next({ request });
+
+  const supabase = createServerClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
+    cookies: {
+      getAll() {
+        return request.cookies.getAll();
+      },
+      setAll(cookiesToSet, headers) {
+        cookiesToSet.forEach(({ name, value }) =>
+          request.cookies.set(name, value),
+        );
+        response = NextResponse.next({ request });
+        cookiesToSet.forEach(({ name, value, options }) =>
+          response.cookies.set(name, value, options),
+        );
+        // The library asks us to attach no-store headers so a CDN never caches
+        // one visitor's refreshed session token for another (CLAUDE.md §6 keeps
+        // audio on R2, but app responses still pass through Vercel's edge).
+        for (const [key, value] of Object.entries(headers)) {
+          response.headers.set(key, value);
+        }
+      },
+    },
+  });
+
+  // Do not run code between createServerClient and getClaims(): a refresh that
+  // lands here writes new cookies onto `response`. getClaims verifies the JWT
+  // locally (no round-trip to the Auth server on every navigation).
+  await supabase.auth.getClaims();
+
+  return response;
+}

diff --git a/src/app/agent/[slug]/page.tsx b/src/app/agent/[slug]/page.tsx
new file mode 100644
