+++ b/src/app/agent/[slug]/page.tsx
@@ -0,0 +1,131 @@
+import Link from "next/link";
+import { notFound } from "next/navigation";
+
+import { WorkTitle } from "@/components/work-title";
+import { AGENT_TYPE_LABELS, type AgentType } from "@/lib/ledger/types";
+import { createClient } from "@/lib/supabase/server";
+
+type WorkRow = {
+  id: number;
+  title: string;
+  status: "draft" | "live";
+  red_line_certified: boolean;
+  created_at: string;
+};
+
+export async function generateMetadata({
+  params,
+}: {
+  params: Promise<{ slug: string }>;
+}) {
+  const { slug } = await params;
+  const supabase = await createClient();
+  const { data: agent } = await supabase
+    .from("agent")
+    .select("name")
+    .eq("profile_slug", slug)
+    .maybeSingle();
+  return { title: agent ? `${agent.name} · AIRED` : "Contributor · AIRED" };
+}
+
+export default async function AgentPage({
+  params,
+}: {
+  params: Promise<{ slug: string }>;
+}) {
+  const { slug } = await params;
+  const supabase = await createClient();
+
+  const { data: agent } = await supabase
+    .from("agent")
+    .select("id, name, type, version, bio, profile_slug, created_at")
+    .eq("profile_slug", slug)
+    .maybeSingle();
+  if (!agent) notFound();
+
+  // Discography: works this agent appears on. RLS returns live works to anyone,
+  // plus the viewer's own drafts. Dedupe (an agent may have several volleys per
+  // work).
+  const { data: volleyRows } = await supabase
+    .from("public_volley")
+    .select("work:work_id ( id, title, status, red_line_certified, created_at )")
+    .eq("agent_id", agent.id);
+
+  // PostgREST returns the FK embed `work` as a single object (many-to-one); the
+  // query-type inferrer assumes an array, so we cast through unknown.
+  const works: WorkRow[] = [];
+  const seen = new Set<number>();
+  for (const row of (volleyRows ?? []) as unknown as { work: WorkRow | null }[]) {
+    const w = row.work;
+    if (w && !seen.has(w.id)) {
+      seen.add(w.id);
+      works.push(w);
+    }
+  }
+  works.sort((a, b) => a.id - b.id);
+
+  const type = agent.type as AgentType;
+
+  return (
+    <main className="mx-auto w-full max-w-3xl flex-1 px-5 py-10">
+      <header className="mb-8 flex flex-col gap-3">
+        <div className="flex flex-wrap items-center gap-2">
+          <h1 className="text-3xl font-semibold text-foreground">
+            {agent.name}
+          </h1>
+          <span className="rounded-full border border-white/15 bg-white/[0.04] px-2.5 py-0.5 text-[11px] uppercase tracking-[0.14em] text-muted">
+            {AGENT_TYPE_LABELS[type] ?? type}
+          </span>
+          {agent.version ? (
+            <span className="font-mono text-xs text-muted/70">
+              v{agent.version}
+            </span>
+          ) : null}
+        </div>
+        {agent.bio ? (
+          <p className="max-w-2xl text-sm leading-relaxed text-muted">
+            {agent.bio}
+          </p>
+        ) : null}
+      </header>
+
+      <section className="flex flex-col gap-4">
+        <h2 className="text-xs uppercase tracking-[0.18em] text-muted/70">
+          Discography
+        </h2>
+
+        {works.length > 0 ? (
+          <ul className="flex flex-col divide-y divide-white/8 overflow-hidden rounded-xl border border-white/8">
+            {works.map((work) => (
+              <li key={work.id}>
+                <Link
+                  href={`/registry/${work.id}`}
+                  className="flex items-center justify-between gap-4 px-4 py-4 transition hover:bg-white/[0.03]"
+                >
+                  <WorkTitle id={work.id} title={work.title} />
+                  <div className="flex shrink-0 items-center gap-2">
+                    {work.status === "draft" ? (
+                      <span className="rounded-full border border-white/15 px-2.5 py-0.5 text-[10px] uppercase tracking-[0.16em] text-muted">
+                        Draft
+                      </span>
+                    ) : null}
+                    {work.red_line_certified ? (
+                      <span className="rounded-full border border-cert-red/40 px-2.5 py-0.5 text-[10px] uppercase tracking-[0.16em] text-cert-red">
+                        Red Line
+                      </span>
+                    ) : null}
+                  </div>
+                </Link>
+              </li>
+            ))}
+          </ul>
+        ) : (
+          <p className="rounded-xl border border-dashed border-white/12 px-5 py-10 text-center text-sm text-muted">
+            No works yet. As {agent.name} is credited on volleys, the
+            discography fills here.
+          </p>
+        )}
+      </section>
+    </main>
+  );
+}

diff --git a/src/app/registry/[id]/page.tsx b/src/app/registry/[id]/page.tsx
new file mode 100644
index 0000000..5f75f2b
--- /dev/null
+++ b/src/app/registry/[id]/page.tsx
@@ -0,0 +1,181 @@
+import Image from "next/image";
+import { notFound } from "next/navigation";
+
+import { VolleyEditor } from "@/components/ledger/volley-editor";
+import { VolleyTrail, type TrailVolley } from "@/components/ledger/volley-trail";
+import { WorkTitle } from "@/components/work-title";
+import { type ContributorSummary } from "@/lib/agents/actions";
+import { formatCatalogId } from "@/lib/catalog";
+import { formatDuration } from "@/lib/format";
+import {
+  type AgentType,
+  type DeltaType,
+  type VolleyOrigin,
+  type VolleyRole,
+} from "@/lib/ledger/types";
+import { getCurrentUser } from "@/lib/supabase/auth";
+import { createClient } from "@/lib/supabase/server";
+
+export async function generateMetadata({
+  params,
+}: {
+  params: Promise<{ id: string }>;
+}) {
+  const { id } = await params;
+  const supabase = await createClient();
+  const { data: work } = await supabase
+    .from("work")
+    .select("id, title")
+    .eq("id", Number(id))
+    .maybeSingle();
+  return {
+    title: work
+      ? `${formatCatalogId(work.id)} · "${work.title}" · AIRED`
+      : "Work · AIRED",
+  };
+}
+
+type VolleyRecord = {
+  id: string;
+  seq: number | string;
+  role: VolleyRole;
+  origin: VolleyOrigin;
+  delta_type: DeltaType;
+  private_hash: string | null;
+  agent: {
+    id: string;
+    name: string;
+    profile_slug: string | null;
+    type: AgentType;
+  } | null;
+};
+
+export default async function WorkPage({
+  params,
+}: {
+  params: Promise<{ id: string }>;
+}) {
+  const { id } = await params;
+  const workId = Number(id);
+  if (!Number.isInteger(workId) || workId <= 0) notFound();
+
+  const supabase = await createClient();
+  const user = await getCurrentUser();
+
+  // RLS returns live works to anyone and drafts only to their creator, so an
+  // unauthorized draft simply 404s.
+  const { data: work } = await supabase
+    .from("work")
+    .select(
+      "id, title, artwork_url, status, red_line_certified, duration_seconds, descriptors, creator_id, created_at",
+    )
+    .eq("id", workId)
+    .maybeSingle();
+  if (!work) notFound();
+
+  const isOwner = !!user && user.id === work.creator_id;
+
+  const { data: volleyData } = await supabase
+    .from("public_volley")
+    .select(
+      "id, seq, role, origin, delta_type, private_hash, agent:agent_id ( id, name, profile_slug, type )",
+    )
+    .eq("work_id", workId)
+    .order("seq", { ascending: true });
+
+  // The FK embed `agent` is a single object at runtime (many-to-one); the
+  // query-type inferrer assumes an array, so we cast through unknown.
+  const volleys: TrailVolley[] = (
+    (volleyData ?? []) as unknown as VolleyRecord[]
+  ).map((v) => ({
+      id: v.id,
+      seq: v.seq,
+      role: v.role,
+      origin: v.origin,
+      delta_type: v.delta_type,
+      private_hash: v.private_hash,
+      agent: v.agent,
+    }),
+  );
+
+  const descriptors: string[] = Array.isArray(work.descriptors)
+    ? work.descriptors
+    : [];
+
+  let agents: ContributorSummary[] = [];
+  let suggestedSeq = 0;
+  if (isOwner) {
+    const { data: agentData } = await supabase
+      .from("agent")
+      .select("id, name, type, profile_slug")
+      .order("name", { ascending: true });
+    agents = (agentData ?? []) as ContributorSummary[];
+    const maxSeq = volleys.reduce((m, v) => Math.max(m, Number(v.seq)), -1);
+    suggestedSeq = volleys.length ? Math.floor(maxSeq) + 1 : 0;
+  }
+
+  return (
+    <main className="mx-auto w-full max-w-3xl flex-1 px-5 py-10">
+      <header className="mb-8 flex flex-col gap-5 sm:flex-row sm:items-start">
+        {work.artwork_url ? (
+          <Image
+            src={work.artwork_url}
+            alt={`Artwork for ${work.title}`}
+            width={128}
+            height={128}
+            className="size-32 shrink-0 rounded-xl border border-white/10 object-cover"
+            unoptimized
+          />
+        ) : (
+          <div className="flex size-32 shrink-0 items-center justify-center rounded-xl border border-dashed border-white/12 text-[10px] uppercase tracking-[0.16em] text-muted/50">
+            no art
+          </div>
+        )}
+
+        <div className="flex flex-col gap-3">
+          <WorkTitle id={work.id} title={work.title} size="lg" />
+          <div className="flex flex-wrap items-center gap-2 text-xs text-muted">
+            <span
+              className={
+                work.status === "live"
+                  ? "rounded-full border border-emerald-400/40 px-2.5 py-0.5 uppercase tracking-[0.14em] text-emerald-300"
