@@ -0,0 +1,20 @@
+// Small display helpers shared across pages.
+
+// Render a duration as m:ss (or h:mm:ss past an hour). There is no length cap on
+// AIRED works (CLAUDE.md §1.4), so this grows into hours naturally.
+export function formatDuration(totalSeconds: number | null | undefined): string {
+  if (
+    totalSeconds == null ||
+    !Number.isFinite(totalSeconds) ||
+    totalSeconds < 0
+  ) {
+    return "—";
+  }
+  const s = Math.round(totalSeconds);
+  const hours = Math.floor(s / 3600);
+  const minutes = Math.floor((s % 3600) / 60);
+  const seconds = s % 60;
+  const mm = hours > 0 ? String(minutes).padStart(2, "0") : String(minutes);
+  const ss = String(seconds).padStart(2, "0");
+  return hours > 0 ? `${hours}:${mm}:${ss}` : `${mm}:${ss}`;
+}

diff --git a/src/lib/ledger/actions.ts b/src/lib/ledger/actions.ts
new file mode 100644
index 0000000..4171bb6
--- /dev/null
+++ b/src/lib/ledger/actions.ts
@@ -0,0 +1,133 @@
+"use server";
+
+import { revalidatePath } from "next/cache";
+
+import { createClient } from "@/lib/supabase/server";
+import { sanitizeReference } from "./sanitizeReference";
+import {
+  canonicalCraft,
+  CREATOR_KEY_REF,
+  provenanceHash,
+  sealCraft,
+  type Craft,
+} from "./seal";
+import {
+  DELTA_TYPES,
+  VOLLEY_ORIGINS,
+  VOLLEY_ROLES,
+  type DeltaType,
+  type VolleyOrigin,
+  type VolleyRole,
+} from "./types";
+
+export type DeclareVolleyInput = {
+  workId: number;
+  seq: number;
+  agentId: string;
+  role: VolleyRole;
+  origin: VolleyOrigin;
+  deltaType: DeltaType;
+  craft: Craft;
+};
+
+export type DeclareVolleyResult =
+  | {
+      ok: true;
+      sanitized: {
+        matched: boolean;
+        unknownReference: boolean;
+        descriptors: string[];
+      };
+    }
+  | { ok: false; error: string };
+
+// Declare one volley: seal the craft and write the paired private + public rows
+// atomically (Phase 2 brief part 2). Order: sanitize → hash → encrypt → one
+// atomic RPC that inserts private_volley + public_volley (+ merges descriptors)
+// in a single transaction. If anything fails, nothing is written.
+export async function declareVolley(
+  input: DeclareVolleyInput,
+): Promise<DeclareVolleyResult> {
+  const supabase = await createClient();
+  const {
+    data: { user },
+  } = await supabase.auth.getUser();
+  if (!user) {
+    return { ok: false, error: "Sign in to declare a volley." };
+  }
+
+  // Validate the shape vocabulary (these are reachable via direct POST).
+  if (!(VOLLEY_ROLES as readonly string[]).includes(input.role)) {
+    return { ok: false, error: "Unknown role." };
+  }
+  if (!(VOLLEY_ORIGINS as readonly string[]).includes(input.origin)) {
+    return { ok: false, error: "Unknown origin." };
+  }
+  if (!(DELTA_TYPES as readonly string[]).includes(input.deltaType)) {
+    return { ok: false, error: "Unknown delta type." };
+  }
+  if (!input.agentId) {
+    return { ok: false, error: "Credit a contributor for this volley." };
+  }
+  if (!Number.isFinite(input.seq)) {
+    return { ok: false, error: "Enter a sequence number (e.g. 0, 1, 1.5)." };
+  }
+
+  // Reference-sanitizer at the boundary, BEFORE any public write. The server
+  // re-runs it regardless of what the client sent — names never reach public.
+  const sanitized = sanitizeReference(input.craft.style_reference_raw ?? "");
+
+  // Seal the verbatim craft. The RAW style reference is sealed; only sanitized
+  // descriptors (never a name) are eligible for the public descriptor set.
+  const craft: Craft = {
+    prompt: input.craft.prompt ?? "",
+    style_reference_raw: input.craft.style_reference_raw ?? "",
+    rejected_branches: input.craft.rejected_branches ?? "",
+    rationale: input.craft.rationale ?? "",
+  };
+
+  let ciphertext: string;
+  let privateHash: string;
+  try {
+    const canonical = canonicalCraft(craft);
+    privateHash = provenanceHash(canonical);
+    ciphertext = sealCraft(canonical);
+  } catch (e) {
+    return {
+      ok: false,
+      error: e instanceof Error ? e.message : "Failed to seal the craft.",
+    };
+  }
+
+  const publicDescriptors = sanitized.unknownReference
+    ? []
+    : sanitized.descriptors;
+
+  // One atomic transaction (SECURITY INVOKER → RLS scopes it to the owner).
+  const { error } = await supabase.rpc("declare_volley", {
+    p_work_id: input.workId,
+    p_seq: input.seq,
+    p_agent_id: input.agentId,
+    p_role: input.role,
+    p_origin: input.origin,
+    p_delta_type: input.deltaType,
+    p_private_hash: privateHash,
+    p_ciphertext: ciphertext,
+    p_creator_key_ref: CREATOR_KEY_REF,
+    p_public_descriptors: publicDescriptors,
+  });
+  if (error) {
+    return { ok: false, error: error.message };
+  }
+
+  revalidatePath(`/registry/${input.workId}`);
+  revalidatePath("/registry");
+  return {
+    ok: true,
+    sanitized: {
+      matched: sanitized.matched,
+      unknownReference: sanitized.unknownReference,
+      descriptors: publicDescriptors,
+    },
+  };
+}

diff --git a/src/lib/ledger/sanitizeReference.ts b/src/lib/ledger/sanitizeReference.ts
new file mode 100644
index 0000000..4e06bd2
--- /dev/null
+++ b/src/lib/ledger/sanitizeReference.ts
@@ -0,0 +1,126 @@
+// The reference-sanitizer (CLAUDE.md Rule 2, Phase 2 brief part 3).
+//
+// Runs at the input boundary, BEFORE any public write. It is a PURE function so
+// the same logic powers the live preview in the editor (client) and the hard
+// enforcement in the server action (server) — defense in depth: even if the
+// client sends a raw name, the server only ever writes this module's sanitized
+// output to public data.
+//
+// Hard guarantee: no third-party artist/song/band name reaches `work`,
+// `public_volley`, `certification`, or any searchable column. The raw string is
+// kept ONLY in the encrypted private volley.
+
+import { descriptorDictionary } from "./descriptorDictionary";
+
+export type SanitizeResult = {
+  /** The original text, exactly as typed. Sealed into private craft ONLY. */
+  raw: string;
+  /** A known dictionary reference was matched and mapped to descriptors. */
+  matched: boolean;
+  /** A reference to an unknown proper noun (a name) — must not go public. */
+  unknownReference: boolean;
+  /** Safe text for public surfaces, or null when nothing may be written. */
+  publicText: string | null;
+  /** Sanitized descriptor tokens for the public, searchable descriptor set. */
+  descriptors: string[];
+  /** UI hint: ask the creator to describe the sound instead of naming it. */
+  promptForDescriptors: boolean;
+};
+
+// Normalize for matching: lowercase, drop quotes, collapse whitespace.
+function normalize(s: string): string {
+  return s
+    .toLowerCase()
+    .replace(/[“”"'’`]/g, "")
+    .replace(/\s+/g, " ")
+    .trim();
+}
+
+function splitDescriptors(s: string): string[] {
+  return s
+    .split(",")
+    .map((d) => d.trim())
+    .filter(Boolean);
+}
+
+// An explicit "make it sound like <something named>" framing.
+const REFERENCE_PATTERN =
+  /(?:sounds?\s+like|sound\s+like|in\s+the\s+style\s+of|styled?\s+after|reminiscent\s+of|reminds?\s+me\s+of|à\s+la|a\s+la|\blike\b)\s+(.+)$/i;
+
+// Does the captured target contain a capitalized word (a likely name)?
+// Unicode-aware so accented names ("Beyoncé", "Sigur Rós") are caught too.
+function hasProperNoun(captured: string): boolean {
+  const cleaned = captured.replace(/[“”"'’`.!?]/g, " ").trim();
+  if (!cleaned) return false;
+  return cleaned.split(/\s+/).some((w) => /^\p{Lu}[\p{L}\p{N}'’-]*$/u.test(w));
+}
+
+// A short Title-Case phrase with no descriptor list reads like a bare name
+// ("Madonna", "Daft Punk", "The Beatles") rather than a genre ("80s new wave").
+// Conservative on purpose: any lowercase word, a comma, or >4 words spares it,
+// because creators type genres/descriptors in lowercase, comma-separated lists.
+function looksLikeBareName(s: string): boolean {
+  if (s.includes(",")) return false;
+  const words = s.split(/\s+/).filter(Boolean);
+  if (words.length === 0 || words.length > 4) return false;
+  const alpha = words.filter((w) => /\p{L}/u.test(w));
+  if (alpha.length === 0) return false;
+  return alpha.every((w) => /^\p{Lu}/u.test(w));
+}
+
+export function sanitizeReference(input: string): SanitizeResult {
+  const raw = input ?? "";
+  const trimmed = raw.trim();
+
+  if (!trimmed) {
+    return {
+      raw,
+      matched: false,
+      unknownReference: false,
+      publicText: "",
+      descriptors: [],
+      promptForDescriptors: false,
+    };
+  }
+
+  const norm = normalize(trimmed);
+
+  // 1) Known reference → replace wholesale with its descriptors. The name is
+  //    discarded from the public path entirely.
+  for (const entry of descriptorDictionary) {
+    if (entry.aliases.some((alias) => norm.includes(normalize(alias)))) {
+      return {
+        raw,
+        matched: true,
+        unknownReference: false,
+        publicText: entry.descriptors,
+        descriptors: splitDescriptors(entry.descriptors),
+        promptForDescriptors: false,
+      };
+    }
+  }
+
+  // 2) An explicit "like <Name>" reference, or a bare Title-Case name → nothing
+  //    may be written publicly; the raw stays sealed and the UI prompts.
+  const m = trimmed.match(REFERENCE_PATTERN);
+  if ((m && hasProperNoun(m[1])) || looksLikeBareName(trimmed)) {
+    return {
+      raw,
+      matched: false,
+      unknownReference: true,
+      publicText: null,
+      descriptors: [],
+      promptForDescriptors: true,
+    };
+  }
+
+  // 3) Plain genres / sonic descriptors → they belong to no one, pass through.
+  return {
+    raw,
+    matched: false,
+    unknownReference: false,
+    publicText: trimmed,
+    descriptors: splitDescriptors(trimmed),
+    promptForDescriptors: false,
+  };
+}

diff --git a/src/lib/ledger/seal.ts b/src/lib/ledger/seal.ts
new file mode 100644
index 0000000..6becca7
--- /dev/null
+++ b/src/lib/ledger/seal.ts
@@ -0,0 +1,95 @@
+// Sealing the craft — SERVER ONLY (CLAUDE.md Rule 1, Phase 2 LOCKED DECISIONS).
+//
+// Option A: server-sealed. We encrypt the private_volley craft at the
+// application layer, in the Node.js runtime, with AES-256-GCM. The key lives in
+// env var AIRED_VOLLEY_ENC_KEY (base64, 32 bytes) and NEVER reaches the browser.
+// Importing `node:crypto` keeps this module off client bundles — never import it
+// into a Client Component.
+//
+// creator_key_ref records the scheme and is the upgrade seam to Option B
+// (client-sealed, creator-passphrase-derived key) with no schema change.
+
+import {
+  createCipheriv,
+  createDecipheriv,
+  createHash,
+  randomBytes,
+} from "node:crypto";
+
+export type Craft = {
+  prompt: string;
+  style_reference_raw: string;
+  rejected_branches: string;
+  rationale: string;
+};
+
+export const CREATOR_KEY_REF = "server:aes-256-gcm:v1";
+
+// Canonical plaintext: JSON of the four craft fields with sorted keys, UTF-8.
+// Deterministic, so the creator can later re-derive the same hash from decrypted
+// content and prove the sealed trail matches the public skeleton.
+export function canonicalCraft(craft: Craft): string {
+  const obj: Record<string, string> = {
+    prompt: craft.prompt ?? "",
+    style_reference_raw: craft.style_reference_raw ?? "",
+    rejected_branches: craft.rejected_branches ?? "",
+    rationale: craft.rationale ?? "",
+  };
+  const sorted = Object.keys(obj)
+    .sort()
+    .reduce<Record<string, string>>((acc, key) => {
+      acc[key] = obj[key];
+      return acc;
+    }, {});
+  return JSON.stringify(sorted);
+}
+
+// hex SHA-256 of the canonical plaintext → public_volley.private_hash.
+export function provenanceHash(canonical: string): string {
+  return createHash("sha256").update(canonical, "utf8").digest("hex");
+}
+
+function loadKey(): Buffer {
+  const b64 = process.env.AIRED_VOLLEY_ENC_KEY;
+  if (!b64) {
+    throw new Error(
+      "AIRED_VOLLEY_ENC_KEY is not set. Generate one with `openssl rand -base64 32` and set it as a server-only env var (locally in .env.local and in Vercel).",
+    );
+  }
+  const key = Buffer.from(b64, "base64");
+  if (key.length !== 32) {
+    throw new Error(
+      `AIRED_VOLLEY_ENC_KEY must decode to 32 bytes (got ${key.length}). Generate one with \`openssl rand -base64 32\`.`,
+    );
+  }
+  return key;
+}
+
+// Seal plaintext → base64(iv ‖ authTag ‖ ciphertext). Per-row random 12-byte IV.
+export function sealCraft(plaintext: string): string {
+  const key = loadKey();
+  const iv = randomBytes(12);
+  const cipher = createCipheriv("aes-256-gcm", key, iv);
+  const ciphertext = Buffer.concat([
+    cipher.update(plaintext, "utf8"),
+    cipher.final(),
+  ]);
+  const authTag = cipher.getAuthTag(); // 16 bytes
+  return Buffer.concat([iv, authTag, ciphertext]).toString("base64");
+}
+
+// Inverse of sealCraft. private_volley is never served; this exists for the
+// creator-side "prove authorship on demand" path and for round-trip tests.
+export function openCraft(packed: string): string {
+  const key = loadKey();
+  const buf = Buffer.from(packed, "base64");
+  const iv = buf.subarray(0, 12);
+  const authTag = buf.subarray(12, 28);
+  const ciphertext = buf.subarray(28);
+  const decipher = createDecipheriv("aes-256-gcm", key, iv);
+  decipher.setAuthTag(authTag);
+  return Buffer.concat([
+    decipher.update(ciphertext),
+    decipher.final(),
+  ]).toString("utf8");
+}

