+  // surface each contributor exactly once (carbon and silicon, by name) in the
+  // order they first appear in the trail.
+  const { data: volleys, error: vErr } = await supabase
+    .from("public_volley")
+    .select("seq, agent:agent_id ( name, type )")
+    .eq("work_id", workId)
