+    // otherwise step back one track.
+    if (audio && audio.currentTime > 3) {
+      audio.currentTime = 0;
+      setCurrentTime(0);
+      return;
+    }
+    const i = indexRef.current;
+    if (i > 0) {
+      pendingPlayRef.current = true;
+      setIndex(i - 1);
+    } else if (audio) {
+      audio.currentTime = 0;
+      setCurrentTime(0);
+    }
