+      setBuffering(true);
+      setLoadError(false);
+      setCurrentTime(0);
+    };
+    const onEmptied = () => {
+      setBuffering(false);
+      setCurrentTime(0);
+      setDuration(0);
+    };
+    const onEnded = () => endedRef.current();
