+    return () => {
+      cancelled = true;
+      if (hlsRef.current) {
+        hlsRef.current.destroy();
+        hlsRef.current = null;
+      }
+    };
+  }, [currentUrl, attempt]);
+
+  // The stable half of the API. Memoized so its identity changes only when these
+  // values actually change — NOT on every currentTime tick — keeping non-clock
+  // consumers (e.g. feed cards) from re-rendering several times a second.
+  const value = useMemo<PlayerContextValue>(
+    () => ({
+      queue,
+      index,
+      current,
+      isPlaying,
+      duration,
+      buffering,
+      loadError,
+      playQueue,
+      toggle,
+      play,
+      pause,
+      next,
+      prev,
+      seek,
+      seekToTime,
+      retry,
+    }),
+    [
+      queue,
+      index,
+      current,
+      isPlaying,
+      duration,
+      buffering,
+      loadError,
+      playQueue,
+      toggle,
+      play,
+      pause,
+      next,
+      prev,
+      seek,
+      seekToTime,
+      retry,
+    ],
+  );
+
+  return (
+    <PlayerContext.Provider value={value}>
+      <PlayerClockContext.Provider value={currentTime}>
+        {children}
+      </PlayerClockContext.Provider>
+      <audio ref={audioRef} preload="metadata" />
+    </PlayerContext.Provider>
+  );
+}

