diff --git a/src/lib/artwork/upload-client.ts b/src/lib/artwork/upload-client.ts
new file mode 100644
index 0000000..3de0341
--- /dev/null
+++ b/src/lib/artwork/upload-client.ts
@@ -0,0 +1,47 @@
+"use client";
+
+import { createClient } from "@/lib/supabase/client";
+
+// Shared browser-side artwork upload (EDIT & TIDY). One path to the PUBLIC
+// `artwork` bucket, owner-folder scoped (the signed-in uid is segment 1 — the
+// same shape the upload form writes), reused by:
+//   • the in-place work editor — replace a work's artwork_url, and
+//   • "Upload a cover" in Manage — set an album's cover_url from a device image.
+// Returns both the storage path and the public URL; callers persist the URL
+// through their owner-scoped server action. Large audio never routes through the
+// server; small images go straight to Storage from the browser, same as upload.
+
+function fileExt(name: string, fallback: string): string {
+  const ext = name.split(".").pop()?.toLowerCase().replace(/[^a-z0-9]/g, "");
+  return ext && ext.length <= 5 ? ext : fallback;
+}
+
+function newId(): string {
+  return typeof crypto !== "undefined" && "randomUUID" in crypto
+    ? crypto.randomUUID()
+    : `${Date.now()}-${Math.random().toString(36).slice(2)}`;
+}
+
+export type UploadedArtwork = { path: string; publicUrl: string };
+
+export async function uploadArtworkImage(file: File): Promise<UploadedArtwork> {
+  const supabase = createClient();
+  const {
+    data: { user },
+  } = await supabase.auth.getUser();
+  if (!user) throw new Error("Your session expired — log in again.");
+
+  const path = `${user.id}/${newId()}/cover.${fileExt(file.name, "png")}`;
+  const upload = await supabase.storage.from("artwork").upload(path, file, {
+    upsert: false,
+    contentType: file.type || undefined,
+    cacheControl: "3600",
+  });
+  if (upload.error) {
+    throw new Error(`Artwork upload failed: ${upload.error.message}`);
+  }
+
+  const publicUrl = supabase.storage.from("artwork").getPublicUrl(path).data
+    .publicUrl;
+  return { path, publicUrl };
+}

diff --git a/src/lib/ledger/sanitizeReference.ts b/src/lib/ledger/sanitizeReference.ts
index 4e06bd2..d45c5e6 100644
--- a/src/lib/ledger/sanitizeReference.ts
+++ b/src/lib/ledger/sanitizeReference.ts
@@ -124,3 +124,51 @@ export function sanitizeReference(input: string): SanitizeResult {
     promptForDescriptors: false,
   };
 }
+
+export type DescriptorSanitizeResult = {
+  /** Safe, de-duplicated descriptor tokens for the public, searchable set. */
+  descriptors: string[];
+  /** Tokens that read like a third-party name and were removed (Rule 2). */
+  dropped: string[];
+};
+
+// Sanitize a free-text descriptor LIST (the in-place work editor — EDIT & TIDY).
+// The editor lets a creator retype the public descriptors directly, so the SAME
+// reference-sanitizer that guards the upload/volley path runs here too: every
+// comma- or newline-separated token is passed through `sanitizeReference`, so a
+// bare artist name is dropped (never public — Rule 2) while genres/descriptors
+// pass through. Known references expand to their descriptors and the name is
+// discarded. Output mirrors the `declare_volley` merge: split, trim, drop blanks,
+// de-duplicate (case-insensitive) with first-seen order preserved. PURE, so the
+// editor's live preview (client) and the `updateWork` enforcement (server) agree.
+export function sanitizeDescriptorList(input: string): DescriptorSanitizeResult {
+  const seen = new Set<string>();
+  const descriptors: string[] = [];
+  const droppedSeen = new Set<string>();
+  const dropped: string[] = [];
+
+  const tokens = (input ?? "")
+    .split(/[\n,]/)
+    .map((t) => t.trim())
+    .filter(Boolean);
+
+  for (const token of tokens) {
+    const r = sanitizeReference(token);
+    if (r.unknownReference) {
+      const key = token.toLowerCase();
+      if (!droppedSeen.has(key)) {
+        droppedSeen.add(key);
+        dropped.push(token);
+      }
+      continue;
+    }
+    for (const d of r.descriptors) {
+      const key = d.toLowerCase();
+      if (seen.has(key)) continue;
+      seen.add(key);
+      descriptors.push(d);
+    }
+  }
+
+  return { descriptors, dropped };
+}

