+    const objects = (listed.Contents ?? [])
+      .map((o) => ({ Key: o.Key }))
+      .filter((o) => o.Key);
+
+    if (objects.length > 0) {
+      await r2.send(
+        new DeleteObjectsCommand({
+          Bucket: bucket,
+          Delete: { Objects: objects, Quiet: true },
+        }),
+      );
+      deleted += objects.length;
+    }
+
+    continuationToken = listed.IsTruncated
+      ? listed.NextContinuationToken
+      : undefined;
+  } while (continuationToken);
+
+  return deleted;
+}

