@@ -0,0 +1,202 @@
+"use client";
+
+import Link from "next/link";
+import { useMemo, useState } from "react";
+import { useRouter } from "next/navigation";
+
+import { HandleHint, useHandleCheck } from "@/components/identity/handle-field";
+import {
+  emptyPick,
+  ImageField,
+  type ImagePick,
+  resolveImagePick,
+} from "@/components/identity/image-field";
+import { updateIdentity } from "@/lib/identity/actions";
+import { handleError, slugifyHandle } from "@/lib/identity/handle";
+
+// The identity editor form (/settings) — the same fields the first-run wizard
+// sets, available anytime. Saves through updateIdentity (owner RLS). Shares the
+// handle live-check and image picker with the wizard.
+
+const inputClass =
+  "w-full rounded-lg border border-white/10 bg-white/5 px-3.5 py-2.5 text-base text-foreground outline-none transition placeholder:text-muted/60 focus:border-cert-red/60 focus:bg-white/[0.07] focus:ring-1 focus:ring-cert-red/40 disabled:opacity-60";
+const labelText = "text-xs font-medium text-muted";
+const primaryBtn =
+  "rounded-lg bg-cert-red px-5 py-2.5 text-sm font-medium text-white shadow-[0_0_18px_-6px_var(--cert-red)] transition hover:brightness-110 disabled:cursor-not-allowed disabled:opacity-60";
+
+type Initial = {
+  displayName: string;
+  handle: string;
+  bio: string;
+  avatarUrl: string | null;
+  mascotName: string;
+  mascotAvatarUrl: string | null;
+};
+
+export function IdentityEditor({ initial }: { initial: Initial }) {
+  const router = useRouter();
+  const [displayName, setDisplayName] = useState(initial.displayName);
+  const [handle, setHandle] = useState(initial.handle);
+  const [bio, setBio] = useState(initial.bio);
+  const [avatar, setAvatar] = useState<ImagePick>(emptyPick(initial.avatarUrl));
+  const [mascotName, setMascotName] = useState(initial.mascotName);
+  const [mascotAvatar, setMascotAvatar] = useState<ImagePick>(
+    emptyPick(initial.mascotAvatarUrl),
+  );
+
+  const [busy, setBusy] = useState(false);
+  const [error, setError] = useState<string | null>(null);
+  const [savedHandle, setSavedHandle] = useState<string | null>(null);
+
+  const handleFmtError = useMemo(
+    () => (handle ? handleError(handle) : null),
+    [handle],
+  );
+  const { avail } = useHandleCheck(handle, handleFmtError);
+
+  async function save() {
+    setError(null);
+    setSavedHandle(null);
+    if (!displayName.trim()) {
+      setError("Give your artist a name.");
+      return;
+    }
+    if (handleFmtError) {
+      setError(handleFmtError);
+      return;
+    }
+    setBusy(true);
+    try {
+      const [avatarUrl, mascotAvatarUrl] = await Promise.all([
+        resolveImagePick(avatar),
+        resolveImagePick(mascotAvatar),
+      ]);
+      const res = await updateIdentity({
+        displayName,
+        handle,
+        bio,
+        avatarUrl,
+        mascotName,
+        mascotAvatarUrl,
+      });
+      if (!res.ok) {
+        setError(res.error);
+        return;
+      }
+      setSavedHandle(slugifyHandle(handle));
+      router.refresh();
+    } catch (e) {
+      setError(e instanceof Error ? e.message : "Couldn't save — try again.");
+    } finally {
+      setBusy(false);
+    }
+  }
+
+  return (
+    <div className="flex flex-col gap-5">
+      <label className="flex flex-col gap-1.5">
+        <span className={labelText}>Artist name</span>
+        <input
+          className={inputClass}
+          value={displayName}
+          onChange={(e) => setDisplayName(e.target.value)}
+          placeholder="Your artist name"
+          maxLength={80}
+          disabled={busy}
+        />
+      </label>
+
+      <label className="flex flex-col gap-1.5">
+        <span className={labelText}>Handle</span>
+        <div className="flex items-center gap-2">
+          <span className="select-none text-sm text-muted/70">
+            ai-red.io/artist/
+          </span>
+          <input
+            className={inputClass}
+            value={handle}
+            onChange={(e) => setHandle(slugifyHandle(e.target.value))}
+            placeholder="your-handle"
+            maxLength={32}
+            disabled={busy}
+            inputMode="text"
+            autoCapitalize="none"
+            spellCheck={false}
+          />
+        </div>
+        <HandleHint handle={handle} fmtError={handleFmtError} avail={avail} />
+      </label>
+
+      <label className="flex flex-col gap-1.5">
+        <span className={labelText}>Bio</span>
+        <textarea
+          className={`${inputClass} min-h-20 resize-y`}
+          value={bio}
+          onChange={(e) => setBio(e.target.value)}
+          placeholder="A line or two about you and your sound."
+          maxLength={600}
+          disabled={busy}
+        />
+      </label>
+
+      <ImageField
+        label="Avatar"
+        pick={avatar}
+        onPick={setAvatar}
+        disabled={busy}
+        shape="round"
+      />
+
+      <div className="h-px bg-white/8" />
+
+      <label className="flex flex-col gap-1.5">
+        <span className={labelText}>Mascot name</span>
+        <input
+          className={inputClass}
+          value={mascotName}
+          onChange={(e) => setMascotName(e.target.value)}
+          placeholder="The emblem of your voices (e.g. Kahotia)"
+          maxLength={80}
+          disabled={busy}
+        />
+      </label>
+
+      <ImageField
+        label="Mascot image"
+        pick={mascotAvatar}
+        onPick={setMascotAvatar}
+        disabled={busy}
+        shape="round"
+      />
+
+      {error ? (
+        <p role="alert" className="text-sm text-cert-red">
+          {error}
+        </p>
+      ) : null}
+
+      {savedHandle ? (
+        <p className="text-sm text-emerald-400">
+          Saved.{" "}
+          <Link
+            href={`/artist/${savedHandle}`}
+            className="underline-offset-4 hover:underline"
+          >
+            View your artist page →
+          </Link>
+        </p>
+      ) : null}
+
+      <div className="flex justify-end">
+        <button
+          type="button"
+          onClick={save}
+          disabled={busy || !displayName.trim() || !!handleFmtError}
+          className={primaryBtn}
+        >
+          {busy ? "Saving…" : "Save identity"}
+        </button>
+      </div>
+    </div>
+  );
+}

diff --git a/src/components/identity/image-field.tsx b/src/components/identity/image-field.tsx
new file mode 100644
index 0000000..3495bb0
--- /dev/null
+++ b/src/components/identity/image-field.tsx
@@ -0,0 +1,122 @@
+"use client";
+
+import { useEffect, useMemo, useRef } from "react";
+
+import { uploadArtworkImage } from "@/lib/artwork/upload-client";
+
+// A device-image picker with a live preview, shared by the first-run wizard and
+// the identity editor (avatar, mascot image, album cover). Uploads happen at
+// submit time via resolveImagePick, mirroring the work editor: small images go
+// straight to the public `artwork` bucket from the browser.
+
+export type ImagePick = {
+  file: File | null;
+  existing: string | null;
+  cleared: boolean;
+};
+
+export function emptyPick(existing: string | null = null): ImagePick {
+  return { file: null, existing, cleared: false };
+}
+
+// Resolve a pick to the Editable an identity action expects: a string (a freshly
+// uploaded URL), null (cleared), or undefined (left as-is).
+export async function resolveImagePick(
+  pick: ImagePick,
+): Promise<string | null | undefined> {
+  if (pick.file) {
+    const { publicUrl } = await uploadArtworkImage(pick.file);
+    return publicUrl;
+  }
+  if (pick.cleared) return null;
+  return undefined;
+}
+
+const fileClass =
+  "w-full rounded-lg border border-dashed border-white/15 bg-white/[0.03] px-3.5 py-3 text-sm text-muted file:mr-3 file:rounded-md file:border-0 file:bg-white/10 file:px-3 file:py-1.5 file:text-sm file:font-medium file:text-foreground hover:file:bg-white/15 disabled:opacity-50";
+
+export function ImageField({
+  label,
+  pick,
+  onPick,
+  disabled,
+  shape,
+}: {
+  label: string;
+  pick: ImagePick;
+  onPick: (next: ImagePick) => void;
+  disabled: boolean;
+  shape: "round" | "square";
+}) {
+  const previewUrl = useMemo(
+    () => (pick.file ? URL.createObjectURL(pick.file) : null),
+    [pick.file],
+  );
+  // Revoke the object URL on change/unmount (cleanup only — no setState here).
+  const lastUrl = useRef<string | null>(null);
+  useEffect(() => {
+    lastUrl.current = previewUrl;
+    return () => {
+      if (lastUrl.current) URL.revokeObjectURL(lastUrl.current);
+    };
+  }, [previewUrl]);
+
+  const shown = pick.file ? previewUrl : pick.cleared ? null : pick.existing;
+  const radius = shape === "round" ? "rounded-full" : "rounded-lg";
+
+  return (
+    <div className="flex flex-col gap-1.5">
+      <span className="text-xs font-medium text-muted">{label}</span>
+      <div className="flex items-center gap-3">
+        {shown ? (
+          // A blob: preview and a stored https URL both render with a plain <img>.
+          // eslint-disable-next-line @next/next/no-img-element
+          <img
+            src={shown}
+            alt=""
+            width={64}
+            height={64}
+            className={`size-16 shrink-0 border border-white/10 object-cover ${radius}`}
+          />
+        ) : (
+          <div
+            className={`flex size-16 shrink-0 items-center justify-center border border-dashed border-white/12 text-[9px] uppercase tracking-[0.16em] text-muted/50 ${radius}`}
+          >
+            none
+          </div>
+        )}
+        <div className="flex min-w-0 flex-1 flex-col gap-1.5">
+          <input
+            className={fileClass}
+            type="file"
+            accept="image/*"
+            disabled={disabled}
+            onChange={(e) => {
+              const f = e.target.files?.[0] ?? null;
+              onPick({ ...pick, file: f, cleared: f ? false : pick.cleared });
+            }}
+          />
+          {(pick.existing || pick.file) && !pick.cleared ? (
+            <button
+              type="button"
+              disabled={disabled}
+              onClick={() => onPick({ ...pick, file: null, cleared: true })}
+              className="self-start text-[11px] text-muted underline-offset-4 hover:text-foreground hover:underline disabled:opacity-50"
+            >
+              Remove
+            </button>
+          ) : pick.cleared ? (
+            <button
+              type="button"
+              disabled={disabled}
+              onClick={() => onPick({ ...pick, cleared: false })}
+              className="self-start text-[11px] text-muted underline-offset-4 hover:text-foreground hover:underline disabled:opacity-50"
+            >
+              Keep current
+            </button>
+          ) : null}
+        </div>
+      </div>
+    </div>
+  );
+}

