+
+    // 5. Compose.
+    const outPath = join(tmp, "clip.mp4");
+    await renderShareClip({
+      framePath,
+      audioPath,
+      band,
+      startSeconds: start,
+      durationSeconds: dur,
+      outPath,
+      fps: config.clipFps,
+    });
+    const bytes = (await stat(outPath)).size;
+
+    // 6. Cache in R2 (public CDN bucket) with a friendly download filename.
+    await uploadToR2({
+      bucket: config.r2HlsBucket,
