+    const elapsedMs = Date.now() - startedAt;
+    log(
+      `work=${workId} DONE clip ${orientation} → ${config.r2HlsBucket}/${key} (${bytes} bytes, ${(elapsedMs / 1000).toFixed(1)}s)`,
+    );
+    return {
+      workId,
+      orientation,
+      key,
+      bytes,
+      durationSeconds: dur,
+      elapsedMs,
+      cached: false,
+    };
+  } finally {
+    await rm(tmp, { recursive: true, force: true }).catch(() => {});
+  }
+}

