+  const { error } = await supabase
+    .from("work")
+    .update({ clip_start_seconds: start, clip_length_seconds: length })
+    .eq("id", workId);
+  if (error) {
+    return { ok: false, error: error.message };
+  }
+
+  revalidatePath("/manage");
+  return { ok: true };
+}

